import os
import io
import re
import json
import time
import uuid
import base64
import hashlib
import tempfile
import subprocess
from urllib.parse import urlparse

from flask import Flask, request, jsonify, send_file
import boto3

try:
    from selenium import webdriver
    from selenium.webdriver.chrome.options import Options as ChromeOptions
    from selenium.webdriver.common.by import By
    from selenium.webdriver.support.ui import WebDriverWait
except Exception:
    webdriver = None

app = Flask(__name__)

AWS_REGION = os.getenv("AWS_REGION", "us-east-1")
S3_BUCKET = os.getenv("S3_BUCKET", "")
S3_PREFIX = os.getenv("S3_PREFIX", "screenshots")
DEFAULT_WIDTH = int(os.getenv("DEFAULT_WIDTH", "1280"))
DEFAULT_HEIGHT = int(os.getenv("DEFAULT_HEIGHT", "720"))
THUMB_WIDTH = int(os.getenv("THUMB_WIDTH", "400"))
THUMB_HEIGHT = int(os.getenv("THUMB_HEIGHT", "225"))
PAGE_LOAD_TIMEOUT = int(os.getenv("PAGE_LOAD_TIMEOUT", "25"))
SHOT_TIMEOUT = int(os.getenv("SHOT_TIMEOUT", "45"))
USE_PHANTOMJS = os.getenv("USE_PHANTOMJS", "0") == "1"
CHROME_BINARY = os.getenv("CHROME_BINARY", "/usr/bin/google-chrome")
CHROMEDRIVER_BINARY = os.getenv("CHROMEDRIVER_BINARY", "chromedriver")
PHANTOMJS_BINARY = os.getenv("PHANTOMJS_BINARY", "phantomjs")
PUBLIC_BASE_URL = os.getenv("PUBLIC_BASE_URL", "").rstrip("/")

s3 = boto3.client("s3", region_name=AWS_REGION) if S3_BUCKET else None


def _valid_url(url):
    try:
        parsed = urlparse(url)
        return parsed.scheme in ("http", "https") and bool(parsed.netloc)
    except Exception:
        return False


def _safe_key_for_url(url):
    digest = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/{digest}.png"


def _ensure_dir(path):
    os.makedirs(path, exist_ok=True)


def _download_from_s3(key, local_path):
    if not s3:
        return False
    try:
        s3.download_file(S3_BUCKET, key, local_path)
        return True
    except Exception:
        return False


def _upload_to_s3(local_path, key, content_type="image/png"):
    if not s3:
        return None
    extra = {"ContentType": content_type, "ACL": "private"}
    s3.upload_file(local_path, S3_BUCKET, key, ExtraArgs=extra)
    if PUBLIC_BASE_URL:
        return f"{PUBLIC_BASE_URL}/{key}"
    return f"s3://{S3_BUCKET}/{key}"


def _make_chrome_driver(width=DEFAULT_WIDTH, height=DEFAULT_HEIGHT):
    if webdriver is None:
        raise RuntimeError("selenium not available")
    options = ChromeOptions()
    options.binary_location = CHROME_BINARY if os.path.exists(CHROME_BINARY) else None
    options.add_argument("--headless=new")
    options.add_argument(f"--window-size={width},{height}")
    options.add_argument("--disable-gpu")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--mute-audio")
    options.add_argument("--disable-extensions")
    options.add_argument("--disable-background-networking")
    options.add_argument("--disable-default-apps")
    options.add_argument("--disable-sync")
    options.add_argument("--metrics-recording-only")
    options.add_argument("--no-first-run")
    options.add_argument("--safebrowsing-disable-auto-update")
    options.add_argument("--disable-popup-blocking")
    options.add_argument("--disable-notifications")
    options.add_argument("--disable-infobars")
    options.add_argument("--force-device-scale-factor=1")
    options.add_argument("--lang=en-US")
    options.add_argument("--user-agent=Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")
    driver = webdriver.Chrome(options=options)
    driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
    return driver


def _make_phantomjs_script(url, out_path, width=DEFAULT_WIDTH, height=DEFAULT_HEIGHT):
    script = f"""
var page = require('webpage').create();
page.viewportSize = {{ width: {width}, height: {height} }};
page.clipRect = {{ top: 0, left: 0, width: {width}, height: {height} }};
page.settings.userAgent = 'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36';
page.settings.loadImages = true;
page.settings.resourceTimeout = 20000;
page.open('{url}', function(status) {{
    if (status !== 'success') {{
        phantom.exit(1);
    }} else {{
        window.setTimeout(function() {{
            page.render('{out_path}');
            phantom.exit(0);
        }}, 3000);
    }}
}});
"""
    return script


def _capture_with_phantomjs(url, out_path):
    with tempfile.NamedTemporaryFile("w", suffix=".js", delete=False) as f:
        f.write(_make_phantomjs_script(url, out_path))
        script_path = f.name
    try:
        subprocess.check_call([PHANTOMJS_BINARY, script_path], timeout=SHOT_TIMEOUT)
    finally:
        try:
            os.unlink(script_path)
        except Exception:
            pass


def _capture_with_chrome(url, out_path, width=DEFAULT_WIDTH, height=DEFAULT_HEIGHT):
    driver = _make_chrome_driver(width, height)
    try:
        driver.get(url)
        time.sleep(3)
        try:
            WebDriverWait(driver, 10).until(lambda d: d.execute_script("return document.readyState") == "complete")
        except Exception:
            pass
        driver.save_screenshot(out_path)
    finally:
        try:
            driver.quit()
        except Exception:
            pass


def _capture_screenshot(url, out_path):
    if USE_PHANTOMJS:
        _capture_with_phantomjs(url, out_path)
    else:
        _capture_with_chrome(url, out_path)


def _make_thumbnail(src_path, thumb_path):
    try:
        from PIL import Image
    except Exception:
        return False
    with Image.open(src_path) as img:
        img = img.convert("RGB")
        img.thumbnail((THUMB_WIDTH, THUMB_HEIGHT))
        canvas = Image.new("RGB", (THUMB_WIDTH, THUMB_HEIGHT), (255, 255, 255))
        x = (THUMB_WIDTH - img.width) // 2
        y = (THUMB_HEIGHT - img.height) // 2
        canvas.paste(img, (x, y))
        canvas.save(thumb_path, format="PNG", optimize=True)
    return True


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"ok": True})


@app.route("/screenshot", methods=["POST", "GET"])
def screenshot():
    url = request.values.get("url", "").strip()
    force = request.values.get("force", "0") == "1"
    if not _valid_url(url):
        return jsonify({"error": "invalid_url"}), 400

    key = _safe_key_for_url(url)
    thumb_key = key.replace(".png", "_thumb.png")

    with tempfile.TemporaryDirectory() as tmpdir:
        full_path = os.path.join(tmpdir, "full.png")
        thumb_path = os.path.join(tmpdir, "thumb.png")

        if not force and s3:
            if _download_from_s3(thumb_key, thumb_path):
                return jsonify({
                    "url": url,
                    "thumbnail": _upload_to_s3(thumb_path, thumb_key) if False else (f"{PUBLIC_BASE_URL}/{thumb_key}" if PUBLIC_BASE_URL else f"s3://{S3_BUCKET}/{thumb_key}"),
                    "key": thumb_key
                })

        try:
            _capture_screenshot(url, full_path)
        except Exception as e:
            return jsonify({"error": "capture_failed", "detail": str(e)}), 500

        if not _make_thumbnail(full_path, thumb_path):
            try:
                import shutil
                shutil.copyfile(full_path, thumb_path)
            except Exception as e:
                return jsonify({"error": "thumbnail_failed", "detail": str(e)}), 500

        uploaded_full = None
        uploaded_thumb = None
        if s3:
            try:
                uploaded_full = _upload_to_s3(full_path, key)
                uploaded_thumb = _upload_to_s3(thumb_path, thumb_key)
            except Exception as e:
                return jsonify({"error": "upload_failed", "detail": str(e)}), 500

        response = {
            "url": url,
            "key": key,
            "thumbnail_key": thumb_key,
            "thumbnail_url": uploaded_thumb,
            "screenshot_url": uploaded_full,
        }
        return jsonify(response)


@app.route("/thumbnail", methods=["GET"])
def thumbnail():
    url = request.args.get("url", "").strip()
    if not _valid_url(url):
        return jsonify({"error": "invalid_url"}), 400

    key = _safe_key_for_url(url).replace(".png", "_thumb.png")
    if s3:
        with tempfile.TemporaryDirectory() as tmpdir:
            local_path = os.path.join(tmpdir, "thumb.png")
            if _download_from_s3(key, local_path):
                return send_file(local_path, mimetype="image/png")
    return jsonify({"error": "not_found"}), 404


@app.route("/capture", methods=["POST"])
def capture():
    data = request.get_json(silent=True) or {}
    url = (data.get("url") or "").strip()
    if not _valid_url(url):
        return jsonify({"error": "invalid_url"}), 400

    key = _safe_key_for_url(url)
    thumb_key = key.replace(".png", "_thumb.png")

    with tempfile.TemporaryDirectory() as tmpdir:
        full_path = os.path.join(tmpdir, "full.png")
        thumb_path = os.path.join(tmpdir, "thumb.png")
        try:
            _capture_screenshot(url, full_path)
            if not _make_thumbnail(full_path, thumb_path):
                raise RuntimeError("thumbnail generation failed")
            uploaded_thumb = _upload_to_s3(thumb_path, thumb_key) if s3 else None
            uploaded_full = _upload_to_s3(full_path, key) if s3 else None
            return jsonify({
                "ok": True,
                "url": url,
                "thumbnail_url": uploaded_thumb,
                "screenshot_url": uploaded_full,
                "thumbnail_key": thumb_key,
                "screenshot_key": key
            })
        except Exception as e:
            return jsonify({"ok": False, "error": str(e)}), 500


